3	/*
4	 * DDx token system — lever/load/fulcrum palette.
5	 *
6	 * Accent lever: #3B5B7A ≈ HSL(210, 36%, 35%). Hextra synthesizes primary
7	 * tints/shades from --primary-hue/saturation/lightness, re-tinting links,
8	 * accents, and focus rings to the DDx lever color.
9	 */
10	
11	:root {
12	  /* Primary scale — drives Hextra's link/accent/focus utilities. */
13	  --primary-hue: 210deg;
14	  --primary-saturation: 36%;
15	  --primary-lightness: 35%;
16	
17	  /* Lever/load/fulcrum accent tokens. */
18	  --ddx-accent-lever:   #3B5B7A;
19	  --ddx-accent-load:    #5A85B0;
20	  --ddx-accent-fulcrum: #2A3F56;
21	  --ddx-accent-brass:   #9A6A2F;
22	
23	  /* Background tokens. */
24	  --ddx-bg-canvas:  #F4EFE6;
25	  --ddx-bg-surface: #FFFDF8;
26	
27	  /* Foreground tokens. */
28	  --ddx-fg-ink:   #17130F;
29	  --ddx-fg-muted: #675F54;
30	
31	  /* Border token. */
32	  --ddx-border-line: #D9CFC0;
33	}
34	
35	.dark {
36	  /* Lift lightness in dark mode so links remain legible on dark backgrounds. */
37	  --primary-lightness: 55%;
38	
39	  --ddx-bg-canvas:  #0F1117;
40	  --ddx-bg-surface: #1A1E2A;
41	
42	  --ddx-fg-ink:   #E8EAF0;
43	  --ddx-fg-muted: #9CA3AF;
44	
45	  --ddx-border-line: #2D3340;
46	  --ddx-accent-brass: #C79B5B;
47	}
