/* ---- Editorial scroll: shared section primitives ---- */

.ddx-home-section-title {
  max-width: 880px;
  margin: 0 0 18px;
  color: var(--ddx-fg-ink);
  font-family: "Inter", ui-sans-serif, system-ui, sans-serif;
  font-size: clamp(28px, 3.6vw, 38px);
  font-weight: 800;
  line-height: 1.08;
}

.ddx-home-section-prose {
  max-width: 720px;
  margin: 0;
  color: var(--ddx-fg-muted);
  font-family: "Newsreader", Georgia, serif;
  font-size: 18px;
  line-height: 1.62;
}

/* ---- Hero: HELIX callout + install ---- */

.ddx-home-helix {
  margin: 28px 0 0;
  padding: 18px 22px;
  border: 1px solid var(--ddx-border-line);
  border-left: 3px solid var(--ddx-accent-load);
  background: color-mix(in srgb, var(--ddx-bg-surface) 86%, transparent);
}

.ddx-home-helix__tag {
  display: inline-block;
  margin-bottom: 6px;
  color: var(--ddx-accent-load);
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.ddx-home-helix p {
  margin: 0;
  color: var(--ddx-fg-ink);
  font-family: "Newsreader", Georgia, serif;
  font-size: 17px;
  line-height: 1.5;
}

.ddx-home-install {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  align-items: center;
  margin-top: 22px;
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 13px;
}

.ddx-home-install code {
  padding: 8px 12px;
  border: 1px solid var(--ddx-border-line);
  background: var(--ddx-bg-surface);
  color: var(--ddx-fg-ink);
  font-family: inherit;
}

.ddx-home-install__or {
  color: var(--ddx-fg-muted);
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

/* ---- Reality / pains / physics / caps / demo / cta spacing ---- */

.ddx-home-reality,
.ddx-home-pains,
.ddx-home-physics,
.ddx-home-caps,
.ddx-home-demo,
.ddx-home-cta {
  padding: 72px 0 16px;
  border-top: 1px solid color-mix(in srgb, var(--ddx-border-line) 70%, transparent);
}

/* ---- Pain cards (6) ---- */

.ddx-home-grid--pains {
  margin-top: 18px;
}

.ddx-home-grid--pains .ddx-home-card {
  aspect-ratio: auto;
  min-height: 200px;
}

.ddx-home-card h3 {
  margin: 0 0 10px;
  color: var(--ddx-fg-ink);
  font-family: "Inter", ui-sans-serif, system-ui, sans-serif;
  font-size: 19px;
  line-height: 1.18;
}

/* ---- Physics 3-line callout ---- */

.ddx-home-physics__lines {
  list-style: none;
  margin: 18px 0 0;
  padding: 0;
  display: grid;
  gap: 14px;
}

.ddx-home-physics__lines li {
  padding: 18px 22px;
  border: 1px solid var(--ddx-border-line);
  background: color-mix(in srgb, var(--ddx-bg-surface) 86%, transparent);
  color: var(--ddx-fg-ink);
  font-family: "Newsreader", Georgia, serif;
  font-size: 20px;
  line-height: 1.45;
}

.ddx-home-physics__tag {
  display: inline-block;
  margin-right: 10px;
  padding: 2px 8px;
  border: 1px solid currentColor;
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  vertical-align: middle;
}

.ddx-home-physics__tag[data-tag="load"]    { color: var(--ddx-accent-load); }
.ddx-home-physics__tag[data-tag="lever"]   { color: var(--ddx-accent-lever); }
.ddx-home-physics__tag[data-tag="fulcrum"] { color: var(--ddx-accent-fulcrum); }

/* ---- Capability table ---- */

.ddx-home-table {
  width: 100%;
  margin-top: 18px;
  border-collapse: collapse;
  font-size: 15px;
}

.ddx-home-table th,
.ddx-home-table td {
  padding: 14px 16px;
  border-bottom: 1px solid var(--ddx-border-line);
  text-align: left;
  vertical-align: top;
}

.ddx-home-table thead th {
  color: var(--ddx-fg-muted);
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  border-bottom: 2px solid var(--ddx-border-line);
}

.ddx-home-table tbody th {
  color: var(--ddx-fg-ink);
  font-family: "Inter", ui-sans-serif, system-ui, sans-serif;
  font-weight: 700;
  width: 22%;
}

.ddx-home-table tbody td {
  color: var(--ddx-fg-muted);
  font-family: "Newsreader", Georgia, serif;
  font-size: 16px;
  line-height: 1.5;
}

.ddx-home-table td:last-child {
  width: 110px;
  white-space: nowrap;
}

.ddx-badge {
  display: inline-block;
  padding: 3px 10px;
  border: 1px solid currentColor;
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.ddx-badge--shipped { color: var(--ddx-accent-lever); }
.ddx-badge--preview { color: var(--ddx-accent-brass); }

/* ---- Demo placeholder ---- */

.ddx-home-demo__frame {
  margin: 18px 0 0;
}

.ddx-home-demo__placeholder {
  display: flex;
  flex-direction: column;
  gap: 14px;
  align-items: flex-start;
  padding: 56px 32px;
  border: 1px dashed var(--ddx-border-line);
  background:
    repeating-linear-gradient(135deg,
      color-mix(in srgb, var(--ddx-bg-surface) 90%, transparent) 0 12px,
      color-mix(in srgb, var(--ddx-bg-canvas) 92%, transparent) 12px 24px);
  min-height: 260px;
}

.ddx-home-demo__badge {
  padding: 3px 10px;
  border: 1px solid var(--ddx-accent-brass);
  color: var(--ddx-accent-brass);
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.ddx-home-demo__placeholder p {
  max-width: 560px;
  margin: 0;
  color: var(--ddx-fg-muted);
  font-family: "Newsreader", Georgia, serif;
  font-size: 17px;
  line-height: 1.5;
}

/* ---- CTA / role entry points ---- */

.ddx-home-roles {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
  margin-top: 18px;
}

.ddx-home-role {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 24px;
  border: 1px solid var(--ddx-border-line);
  background: var(--ddx-bg-surface);
  color: var(--ddx-fg-ink);
  text-decoration: none;
  transition: border-color 120ms ease;
}

.ddx-home-role:hover {
  border-color: var(--ddx-accent-lever);
}

.ddx-home-role__tag {
  color: var(--ddx-accent-brass);
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.ddx-home-role__title {
  color: var(--ddx-fg-ink);
  font-family: "Inter", ui-sans-serif, system-ui, sans-serif;
  font-size: 22px;
  font-weight: 700;
  line-height: 1.12;
}

.ddx-home-role__hint {
  color: var(--ddx-fg-muted);
  font-family: "Newsreader", Georgia, serif;
  font-size: 16px;
  line-height: 1.5;
}

.ddx-home-role__hint code {
  padding: 1px 6px;
  border: 1px solid var(--ddx-border-line);
  background: var(--ddx-bg-canvas);
  font-family: "Space Grotesk", ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 13px;
}

@media (max-width: 820px) {

  .ddx-home-card {
    aspect-ratio: auto;
    min-height: 220px;
  }

  .ddx-home-roles {
    grid-template-columns: 1fr;
  }

  .ddx-home-table tbody th {
    width: auto;
  }

  .ddx-home-table,
  .ddx-home-table thead,
  .ddx-home-table tbody,
  .ddx-home-table tr,
  .ddx-home-table th,
  .ddx-home-table td {
    display: block;
  }

  .ddx-home-table thead {
    display: none;
  }

  .ddx-home-table tr {
    margin-bottom: 14px;
    border: 1px solid var(--ddx-border-line);
  }

  .ddx-home-table th,
  .ddx-home-table td {
    border-bottom: none;
  }
}
